mapper.select:
SELECT DISTINCT A.TRUST_ID, A.PLAN_TYPE, TEMP_T1.MASS_NAME MASS_NAMES_SOURCE, A.MASS_NAMES_TARGET, A.ID WORK_PLAN_ID FROM T_PRD_DISPATCH_SECONDARY B left join T_PRD_WORK_PLAN A ON A . ID = b.WORK_PLAN_ID LEFT JOIN M_WORK_PROCESS C ON C.PROCESS_CD = A.PROCESS_CODE LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (MASS_NAME), ',' ) WITHIN GROUP (ORDER BY WORK_PLAN_ID), '([^,]+)(,\1)+', '\1' ) MASS_NAME, WORK_PLAN_ID FROM T_PRD_WORK_PLAN_LOCATION WHERE MASS_NAME IS NOT NULL GROUP BY WORK_PLAN_ID ) TEMP_T1 ON TEMP_T1.WORK_PLAN_ID = A.ID WHERE A.WORK_DATE = TO_DATE (#{workDate}, 'YYYY-MM-DD') AND A.CLASS_CODE = #{classCode} AND A .PLAN_TYPE = '1' AND C.IS_DIRECT_ACCESS = '1'
AND B.EQUIPMENT_NO = #{macCode}
AND b.WORK_PLAN_ID = #{workPlanId}

SELECT DISTINCT A.TRUST_ID, A.PLAN_TYPE, A.MASS_NAMES_SOURCE, A.MASS_NAMES_TARGET, A.ID WORK_PLAN_ID FROM T_PRD_DISPATCH_SECONDARY B left join T_PRD_WORK_PLAN A ON A . ID = b.WORK_PLAN_ID LEFT JOIN M_WORK_PROCESS C ON C.PROCESS_CD = A.PROCESS_CODE WHERE A.WORK_DATE = TO_DATE (#{workDate}, 'YYYY-MM-DD') AND A.CLASS_CODE = #{classCode} AND A.PLAN_TYPE = '3'
AND B.EQUIPMENT_NO = #{macCode}
AND B.WORK_PLAN_ID = #{workPlanId}

SELECT C.WORK_TIME_START, C.WORK_TIME_END, TBTC.ID TRUST_CARGO_INFO_ID, PP.NOTE_ID WEIGHBRIDGE_ID, NULL MAC_ID, PP.TRUCK_PLATE WORK_MAC_NAME, PP.WEIGH_IN_DT IN_PORT_TIME, TDS.SCN, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TBCI.ID CARGO_INFO_ID, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.CARGO_OWNER_NAME, T1.POUND_REMARK, TO_CHAR(PP.WEIGH_IN_DT,'MM-DD HH24:MI') WEIGH_IN_DT, C.CREATE_BY FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBTC.BUSINESS_NO = PP.PLAN_NO LEFT JOIN T_BUS_TRUST T1 ON T1.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON TBCI.SHIPVOYAGE_ITEM_ID = F. ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON F.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_MAC_WORK_TIME C ON C.WEIGHBRIDGE_ID = PP.NOTE_ID WHERE PP.IS_FINISHED = 0 AND PP.IS_TALLY = 0
AND PP.PORT_CODE = #{portCode}
AND PP.TRUCK_PLATE LIKE #{carNo_like,jdbcType=VARCHAR}
AND TBTC.BUSINESS_NO IN
#{businessNo}

SELECT C.WORK_TIME_START, C.WORK_TIME_END, TBTC.ID TRUST_CARGO_INFO_ID, PP.NOTE_ID WEIGHBRIDGE_ID, NULL MAC_ID, PP.TRUCK_PLATE WORK_MAC_NAME, PP.WEIGH_IN_DT IN_PORT_TIME, TDS.SCN, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TBCI.ID CARGO_INFO_ID, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, T1.POUND_REMARK, TO_CHAR(PP.WEIGH_IN_DT,'MM-DD HH24:MI') WEIGH_IN_DT FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBTC.BUSINESS_NO = PP.PLAN_NO LEFT JOIN T_BUS_TRUST T1 ON T1.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON TBCI.SHIPVOYAGE_ITEM_ID = F. ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON F.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_MAC_WORK_TIME C ON C.WEIGHBRIDGE_ID = PP.NOTE_ID WHERE PP.IS_FINISHED = 0
AND PP.PORT_CODE = #{portCode}
AND PP.TRUCK_PLATE LIKE #{carNo_like,jdbcType=VARCHAR}
AND TBTC.BUSINESS_NO IN
#{businessNo}

SELECT PLAN_TYPE, MASS_NAMES_SOURCE, MASS_NAMES_TARGET, WORK_PLAN_ID, WORK_TIME_START, WORK_TIME_END, TRUST_CARGO_INFO_ID, SHIPVOYAGE_ID, WEIGHBRIDGE_ID, MAC_ID, WORK_MAC_NAME, IN_PORT_TIME, SCN, SHIPVOYAGE_ID, SHIP_NAME, CARGO_INFO_ID, CARGO_CODE, CARGO_NAME, CARGO_OWNER_NAME, POUND_REMARK, WEIGH_IN_DT, CREATE_BY FROM ( SELECT A.PLAN_TYPE, TEMP_T1.MASS_NAME MASS_NAMES_SOURCE, A.MASS_NAMES_TARGET, B.WORK_PLAN_ID, C.WORK_TIME_START, C.WORK_TIME_END, C.CREATE_BY, TBTC.ID TRUST_CARGO_INFO_ID, PP.NOTE_ID WEIGHBRIDGE_ID, NULL MAC_ID, PP.WEIGH_IN_DT IN_PORT_TIME, TDS.SCN, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TBCI.ID CARGO_INFO_ID, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.CARGO_OWNER_NAME, T1.POUND_REMARK, TO_CHAR(PP.WEIGH_IN_DT,'MM-DD HH24:MI') WEIGH_IN_DT, CASE to_char(A.PROCESS_CODE) WHEN '1047' THEN pp.TRUCK_PLATE||'(直)' WHEN '1039' THEN pp.TRUCK_PLATE||'(直)' ELSE pp.TRUCK_PLATE END AS WORK_MAC_NAME FROM T_PRD_DISPATCH_SECONDARY B, T_PRD_WORK_PLAN A LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG ( TO_CHAR (MASS_NAME), ',' ) WITHIN GROUP (ORDER BY WORK_PLAN_ID), '([^,]+)(,\1)+', '\1' ) MASS_NAME, WORK_PLAN_ID FROM T_PRD_WORK_PLAN_LOCATION WHERE MASS_NAME IS NOT NULL GROUP BY WORK_PLAN_ID ) TEMP_T1 ON TEMP_T1.WORK_PLAN_ID = A.ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON A .TRUST_ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP ON TBTC.BUSINESS_NO = PP.PLAN_NO LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON TBCI.SHIPVOYAGE_ITEM_ID = F. ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON F.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_MAC_WORK_TIME C ON C.WEIGHBRIDGE_ID = PP.NOTE_ID LEFT JOIN T_BUS_TRUST T1 ON T1.ID = A.TRUST_ID WHERE A.WORK_DATE = TO_DATE (#{workDate}, 'YYYY-MM-DD') AND A.CLASS_CODE = #{classCode} AND A.PLAN_TYPE = '2' AND A.ID = b.WORK_PLAN_ID AND B.EQUIPMENT_NO = #{macCode}
AND PP.IS_FINISHED = 0 AND PP.IS_TALLY = 0
AND b.WORK_PLAN_ID = #{workPlanId}
AND PP.PORT_CODE = #{portCode}
) TEMP_ALL_T
AND WORK_MAC_NAME LIKE #{carNo_like,jdbcType=VARCHAR}
ORDER BY TEMP_ALL_T.WEIGH_IN_DT, TEMP_ALL_T.SHIP_NAME, TEMP_ALL_T.CARGO_NAME, TEMP_ALL_T.MASS_NAMES_SOURCE
ORDER BY TEMP_ALL_T.MASS_NAMES_SOURCE, TEMP_ALL_T.WEIGH_IN_DT, TEMP_ALL_T.SHIP_NAME, TEMP_ALL_T.CARGO_NAME

SELECT PLAN_TYPE, MASS_NAMES_SOURCE, MASS_NAMES_TARGET, WORK_PLAN_ID, WORK_TIME_START, WORK_TIME_END, TRUST_CARGO_INFO_ID, SHIPVOYAGE_ID, WEIGHBRIDGE_ID, MAC_ID, WORK_MAC_NAME, IN_PORT_TIME, SCN, SHIPVOYAGE_ID, SHIP_NAME, CARGO_INFO_ID, CARGO_CODE, CARGO_NAME, CARGO_OWNER_ID, CARGO_OWNER_NAME, POUND_REMARK, WEIGH_IN_DT FROM ( SELECT A.PLAN_TYPE, TEMP_T1.MASS_NAME MASS_NAMES_SOURCE, A.MASS_NAMES_TARGET, A.ID WORK_PLAN_ID, C.WORK_TIME_START, C.WORK_TIME_END, TBTC.ID TRUST_CARGO_INFO_ID, PP.NOTE_ID WEIGHBRIDGE_ID, NULL MAC_ID, PP.TRUCK_PLATE WORK_MAC_NAME, PP.WEIGH_IN_DT IN_PORT_TIME, TDS.SCN, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME, TBCI.ID CARGO_INFO_ID, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, T1.POUND_REMARK, TO_CHAR(PP.WEIGH_IN_DT,'MM-DD HH24:MI') WEIGH_IN_DT FROM T_PRD_WORK_PLAN A LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG (TO_CHAR(V1.MASS_NAME), ',') WITHIN GROUP (ORDER BY V1.WORK_PLAN_ID), '([^,]+)(,\1)+', '\1' ) MASS_NAME, REGEXP_REPLACE ( LISTAGG (TO_CHAR(V2.WORK_AREA_CD), ',') WITHIN GROUP (ORDER BY V1.WORK_PLAN_ID), '([^,]+)(,\1)+', '\1' ) WORK_AREA_CD, V1.WORK_PLAN_ID FROM T_PRD_WORK_PLAN_LOCATION V1 LEFT JOIN M_STORAGE_YARD V2 ON V1.STOREHOUSE_ID = V2.ID GROUP BY V1.WORK_PLAN_ID ) TEMP_T1 ON TEMP_T1.WORK_PLAN_ID = A.ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON A .TRUST_ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP ON TBTC.BUSINESS_NO = PP.PLAN_NO LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON TBCI.SHIPVOYAGE_ITEM_ID = F. ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON F.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_MAC_WORK_TIME C ON C.WEIGHBRIDGE_ID = PP.NOTE_ID LEFT JOIN T_BUS_TRUST T1 ON T1.ID = A.TRUST_ID WHERE A.WORK_DATE = TO_DATE (#{workDate}, 'YYYY-MM-DD') AND A.CLASS_CODE = #{classCode} AND A.PLAN_TYPE = '2'
AND PP.IS_FINISHED = 0 AND PP.IS_TALLY = 0
AND (TEMP_T1.WORK_AREA_CD = #{workAreaCd} OR TEMP_T1.WORK_AREA_CD IS NULL)
AND PP.PORT_CODE = #{portCode}
) TEMP_ALL_T
AND WORK_MAC_NAME LIKE #{carNo_like,jdbcType=VARCHAR}
ORDER BY TEMP_ALL_T.WEIGH_IN_DT, TEMP_ALL_T.SHIP_NAME, TEMP_ALL_T.CARGO_NAME, TEMP_ALL_T.MASS_NAMES_SOURCE

SELECT PP.TRUCK_PLATE WORK_MAC_NAME, PP.LOCATION, A .PLAN_TYPE, pp.PLAN_NO, PP.PORT_CODE, TEMP_T1.MASS_NAME MASS_NAMES_SOURCE, A.MASS_NAMES_TARGET, C.WORK_TIME_START, C.WORK_TIME_END, TBTC.CARGO_NAME, TBTC. ID TRUST_CARGO_INFO_ID, TDS. ID AS SHIPVOYAGE_ID, PP.NOTE_ID WEIGHBRIDGE_ID, NULL MAC_ID, PP.WEIGH_IN_DT IN_PORT_TIME, TDS. SCN, TDS. ID SHIPVOYAGE_ID, TDS.SHIP_NAME || '_' || F.VOYAGE SHIP_NAME, TBCI. ID CARGO_INFO_ID, TBCI.CARGO_CODE, TBCI.CARGO_NAME, TBCI.cargo_info_no, TBTC.PACKING_CODE, TBTC.PACKING_NAME, TBCI.CARGO_OWNER_NAME, T1.POUND_REMARK, TBVR.DRIVER_NO_ONE, TBVR.DRIVER_NAME_ONE, TBVR.DRIVER_PHONE_ONE, TYT.remark tallRemark, TYT.id tallyId, TYT.del_flag tyt_del_flag, TO_CHAR ( PP.WEIGH_IN_DT, 'MM-DD HH24:MI' ) WEIGH_IN_DT, COALESCE(TYT.CREATE_BY_NAME,C.CREATE_BY_NAME) TALLY_NAME, CASE WHEN A . ID IS NULL THEN '30' ELSE '' END WORK_TIME_STATUS FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBTC.BUSINESS_NO = PP.PLAN_NO LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI. ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON TBCI.SHIPVOYAGE_ITEM_ID = F. ID LEFT JOIN T_PRD_WORK_PLAN A ON TBTC.TRUST_ID = A .TRUST_ID AND A .WORK_DATE = TO_DATE (#{workDate}, 'YYYY-MM-DD') AND A .CLASS_CODE = #{classCode} LEFT JOIN ( SELECT REGEXP_REPLACE ( LISTAGG (TO_CHAR(MASS_NAME), ',') WITHIN GROUP (ORDER BY WORK_PLAN_ID), '([^,]+)(,\1)+', '\1' ) MASS_NAME, WORK_PLAN_ID FROM T_PRD_WORK_PLAN_LOCATION WHERE MASS_NAME IS NOT NULL GROUP BY WORK_PLAN_ID ) TEMP_T1 ON TEMP_T1.WORK_PLAN_ID = A . ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON F.SHIPVOYAGE_ID = TDS. ID LEFT JOIN T_MAC_WORK_TIME C ON C.WEIGHBRIDGE_ID = PP.NOTE_ID LEFT JOIN T_BUS_TRUST T1 ON T1. ID = A .TRUST_ID LEFT JOIN T_BUS_VEHICLE_RESERVATION TBVR ON PP.TSPT_ID = TBVR.TASK_NO left join T_YARD_TALLY TYT on (TYT.WEIGHBRIDGE_ID = pp.NOTE_ID and TYT.del_flag !='1') WHERE PP.IS_FINISHED = 0 AND PP.INV_NO IS NOT NULL
AND PP.PLAN_NO LIKE #{planNo_like,jdbcType=VARCHAR}
AND PP.TRUCK_PLATE LIKE #{carNum_like,jdbcType=VARCHAR}
AND PP.PORT_CODE =#{portCode,jdbcType=VARCHAR}
ORDER BY TDS.SHIP_NAME ASC ,F.VOYAGE ASC, TBCI.CARGO_NAME ASC, PP.WEIGH_IN_DT ASC

SELECT PP.TRUCK_PLATE WORK_MAC_NAME, PP.LOCATION, PP.PLAN_NO, PP.PORT_CODE, C.REGION_NAME ||'-'|| NVL(C.MASS_NAME,'') MASS_NAMES_SOURCE, C.WORK_TIME_START, C.WORK_TIME_END, TBTC.CARGO_NAME, TBTC.ID TRUST_CARGO_INFO_ID, TDS.ID AS SHIPVOYAGE_ID, PP.NOTE_ID WEIGHBRIDGE_ID, NULL MAC_ID, PP.WEIGH_IN_DT IN_PORT_TIME, PP.WEIGH_OUT_DT OUT_PORT_TIME, TDS.SCN, TDS.ID SHIPVOYAGE_ID, TDS.SHIP_NAME || '_' || F.VOYAGE SHIP_NAME, TBCI.ID CARGO_INFO_ID, TBCI.CARGO_CODE, TBCI.CARGO_NAME, tbci.cargo_info_no, TBTC.PACKING_CODE, TBTC.PACKING_NAME, TBCI.CARGO_OWNER_NAME, T1.POUND_REMARK, TO_CHAR( PP.WEIGH_IN_DT, 'MM-DD HH24:MI' ) WEIGH_IN_DT, C.CREATE_BY_NAME TALLY_NAME, TBVR.DRIVER_NO_ONE, TBVR.DRIVER_NAME_ONE, TBVR.DRIVER_PHONE_ONE FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND PP LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBTC.BUSINESS_NO = PP.PLAN_NO LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON TBCI.SHIPVOYAGE_ITEM_ID = F.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON F.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_MAC_WORK_TIME C ON C.WEIGHBRIDGE_ID = PP.NOTE_ID LEFT JOIN T_BUS_TRUST T1 ON T1.ID = TBCI.TRUST_ID LEFT JOIN T_BUS_VEHICLE_RESERVATION TBVR ON PP.TSPT_ID = TBVR.TASK_NO
PP.IS_FINISHED = 1 AND PP.IS_TALLY = 1
AND PP.PLAN_NO LIKE #{planNo_like,jdbcType=VARCHAR}
AND PP.TRUCK_PLATE LIKE #{carNum_like,jdbcType=VARCHAR}
AND PP.PORT_CODE = #{portCode,jdbcType=VARCHAR}
ORDER BY PP.WEIGH_IN_DT DESC

SELECT DISTINCT A . ID, A .WORK_PLAN_ID, A .DIRECTION, A .STOREHOUSE_ID, A .STOREHOUSE_NAME, A .REGION_ID, A .REGION_NAME, A .MASS_ID, A .MASS_NAME, B.CARGO_INFO_ID, C.TYPE FROM T_PRD_WORK_PLAN_LOCATION A LEFT JOIN T_PRD_WORK_PLAN D ON A.WORK_PLAN_ID = D.ID LEFT JOIN T_BUS_TRUST C ON C. ID = D.TRUST_ID LEFT JOIN T_PRD_PORT_STORAGE B ON A .MASS_ID = B.MASS_ID AND B.CLEAN_MASS_SIGN != '1'
AND b.CARGO_INFO_ID = #{cargoInfoId}
WHERE A .WORK_PLAN_ID = #{workPlanId}

mapper.update:
UPDATE T_MAC_WORK_TIME SET
	WORK_TIME_END = #{workTimeEnd, jdbcType=TIMESTAMP},
	UPDATE_BY = #{loginUserId, jdbcType=BIGINT},
	UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR},
	UPDATE_TIME = #{now, jdbcType=TIMESTAMP}
WHERE ID = #{id, jdbcType=BIGINT}

UPDATE WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND
SET IS_TALLY = 1,
	IS_DIRECTION = #{isDirection}
WHERE NOTE_ID = #{noteId}

update
WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND
set
LOCATION = #{location, jdbcType=VARCHAR}
where
NOTE_ID = #{weighbridgeId}

mapper.select:
SELECT
	*
FROM
	T_MAC_WORK_NOW
WHERE
	MAC_ID = #{macId}
AND WORK_DATE = #{workDate}
AND CLASS_CODE = #{classCode}
AND ROWNUM = 1
ORDER BY WORK_DATE DESC, CLASS_CODE DESC

SELECT ID "value",STORAGE_YARD_NM "label" FROM M_STORAGE_YARD

	STORAGE_YARD_NM IN

		#{item}

select note_id,WEIGH_IN_DT,WEIGH_OUT_DT,IS_FINISHED
from "WFG_PORTMIS_POUND".WEIGHT_RECORD_POUND
where note_id = #{noteId}

SELECT tpwp.ID "workPlanId", tpwp.WORK_DATE "workDate", tpwp.CLASS_CODE "classCode", tpwp.CLASS_NAME "className", tpwp.PROCESS_CODE "processCode", tpwp.PROCESS_NAME "processName", tbt.ID "trustId", tbt.trust_no "trustNo", tbci.CARGO_NAME "cargoName", tbci.CARGO_INFO_NO "cargoInfoNo", tbci.CARGO_OWNER_ID "cargoOwnerId", tbci.CARGO_OWNER_NAME "cargoOwnerName" FROM T_BUS_TRUST_CARGO tbtc LEFT JOIN T_PRD_WORK_PLAN tpwp ON TBTC.TRUST_ID = tpwp.TRUST_ID LEFT JOIN T_BUS_TRUST tbt ON TPWP.TRUST_ID = TBT.ID LEFT JOIN T_BUS_CARGO_INFO tbci ON TBTC.CARGO_INFO_ID = tbci.ID LEFT JOIN T_PRD_DISPATCH_SECONDARY tpds ON TPDS.WORK_PLAN_ID = TPWP.ID LEFT JOIN M_MACHINE mm ON mm.ID = tpds.EQUIPMENT_ID WHERE tpwp.PLAN_TYPE = '3'
AND mm.IMEI = #{imei}
AND tpwp.CLASS_CODE = #{classCode}
AND tpwp.WORK_DATE = TO_DATE(#{workDate},'YYYY-MM-DD hh24:mi:ss')

mapper.update:
UPDATE T_YARD_TALLY

	DEL_FLAG = '1',
	UPDATE_BY = #{createBy, jdbcType=BIGINT},
	UPDATE_BY_NAME = #{createByName, jdbcType=VARCHAR},
	UPDATE_TIME = #{createTime, jdbcType=TIMESTAMP}

WHERE ID = #{tallyId, jdbcType=BIGINT}

mapper.select:
SELECT tpps.ID "portStorageId", sum(NVL(tppsd.TON,0)) "ton" FROM T_PRD_PORT_STORAGE tpps LEFT JOIN T_PRD_PORT_STORAGE_DETAIL tppsd ON TPPS.ID = TPPSD.PORT_STORAGE_ID WHERE tpps.ID
#{id,jdbcType=VARCHAR}
GROUP BY tpps.ID

mapper.update:
UPDATE T_PRD_PORT_STORAGE

	TON = #{ton},
	UPDATE_BY = #{createBy, jdbcType=BIGINT},
	UPDATE_BY_NAME = #{createByName, jdbcType=VARCHAR},
	UPDATE_TIME = #{createTime, jdbcType=TIMESTAMP}

WHERE ID = #{id, jdbcType=BIGINT}
